<?php

namespace Tests;

use Illuminate\Foundation\Testing\TestCase as BaseTestCase;

abstract class TestCase extends BaseTestCase
{
    // Test-only RSA key pair generated with openssl_pkey_new().
    // These are used so Passport doesn't try to read the storage/oauth-*.key
    // files, which are owned by Docker's www-data and unreadable locally.
    private const TEST_PRIVATE_KEY = '';

    private const TEST_PUBLIC_KEY = '';

    protected function setUp(): void
    {
        parent::setUp();

        config([
            'passport.private_key' => base64_decode(self::TEST_PRIVATE_KEY),
            'passport.public_key' => base64_decode(self::TEST_PUBLIC_KEY),
        ]);
    }
}
